+fn optimized_tier_plan_rejects_candidate_profile_opcode_mismatch() {
+    let program = Program {
+        constants: vec![Value::Int(42), Value::Int(50), Value::Int(1)],
+        property_pool: vec!["answer".to_string()],
+        instructions: vec![
+            Instruction::NewObject { dst: r(0) },
